<template>
  <div>
    <HeroHeaderDashboard :title="title" :breadcrumbs="breadcrumbs">
      <template #actions>
        <NuxtLink
          class="btn btn--primary"
          :to="`/dashboard/maintenance/packs/${route.params.id}/edit`"
        >
          Editar pack
        </NuxtLink>
      </template>
    </HeroHeaderDashboard>
    <BoxContent>
      <template #content>
        <BoxInformation title="Información" :columns="2">
          <CardInfoDashboard
            v-if="item"
            title="Nombre"
            :description="item.name"
          />
          <CardInfoDashboard
            v-if="item"
            title="Descripción"
            :description="item.description"
          />
          <CardInfoDashboard
            v-if="item"
            title="Texto"
            :description="item.text"
          />
          <CardInfoDashboard
            v-if="item"
            title="Precio"
            :description="`$${item.price?.toLocaleString('es-CL') || '--'}`"
          />
          <CardInfoDashboard
            v-if="item"
            title="Duración (días)"
            :description="item.total_days?.toString() || '--'"
          />
          <CardInfoDashboard
            v-if="item"
            title="Cantidad de anuncios"
            :description="item.total_ads?.toString() || '--'"
          />
          <CardInfoDashboard
            v-if="item"
            title="Destacados"
            :description="item.total_features?.toString() || '--'"
          />
        </BoxInformation>
      </template>
      <template #sidebar>
        <BoxInformation title="Detalles" :columns="1">
          <CardInfoDashboard
            v-if="item"
            title="Fecha de creación"
            :description="formatDate(item.createdAt)"
          />
          <CardInfoDashboard
            v-if="item"
            title="Última modificación"
            :description="formatDate(item.updatedAt)"
          />
        </BoxInformation>
      </template>
    </BoxContent>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from "vue";
import { useRoute } from "vue-router";
import type { Pack } from "@/types/pack";
import { formatDate } from "@/utils/date";

definePageMeta({
  layout: "dashboard",
});

const route = useRoute();
const item = ref<Pack | null>(null);
const apiClient = useApiClient();

const title = computed(() => item.value?.name || "Pack");
const breadcrumbs = computed(() => [
  { label: "Packs", to: "/dashboard/maintenance/packs" },
  ...(item.value?.name ? [{ label: item.value.name }] : []),
]);

const { data: packData } = await useAsyncData(
  `pack-${route.params.id}`,
  async () => {
    const id = route.params.id;
    if (!id) return null;

    const response = (await apiClient("ad-packs", {
      method: "GET",
      params: { filters: { documentId: { $eq: id } } } as unknown as Record<
        string,
        unknown
      >,
    })) as { data: unknown[] };
    const data = Array.isArray(response.data) ? response.data[0] : null;
    if (data) return data;

    const fallback = (await apiClient(`ad-packs/${id}`, { method: "GET" })) as {
      data: unknown;
    };
    return (fallback.data as unknown) || null;
  },
);

item.value = (packData.value as Pack | null) ?? null;
</script>
